const allItems = $input.all();
// 篩選出真正的日誌項（排除 Webhook 原始數據）
const logItems = allItems.filter(i => i.json.Date || i.json.日期 || i.json.Ticker || i.json.代號);

const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'Asia/Taipei' }));
const yyyy = now.getFullYear();
const mm = String(now.getMonth() + 1).padStart(2, '0');
const dd = String(now.getDate()).padStart(2, '0');
const todaySlash = `${yyyy}/${mm}/${dd}`;

const initialCapital = 1000000;
let totalPnL = 0;
let dailyPnL = 0;

logItems.forEach(i => {
    const data = i.json;
    const entryPrice = parseFloat(data.參考進場) || parseFloat(data.成本價) || 0;
    const currentPrice = parseFloat(data.現價) || parseFloat(data.Price) || entryPrice;
    if (entryPrice > 0) {
        const pnl = (currentPrice - entryPrice) * 1000;
        totalPnL += pnl;
        const d = data.Date || data.日期 || "";
        if (d.includes(todaySlash)) dailyPnL += pnl;
    }
});

const formatted = logItems.map(i => {
    const data = i.json;
    const entry = parseFloat(data.參考進場) || parseFloat(data.成本價) || 0;
    const current = parseFloat(data.現價) || 0;
    const p = entry > 0 ? ((current - entry) / entry * 100).toFixed(2) : "0.00";
    return {
        ticker: data.代號 || data.Ticker || "",
        name: data.名稱 || data.Name || "",
        price: entry,
        current: current,
        action: data["AI建議(Buy/Sell)"] || "WAIT",
        profit: (parseFloat(p) >= 0 ? "+" : "") + p + "%",
        time: data.Time || data.時間 || data.Date || data.日期 || ""
    };
});

return {
    json: {
        date: todaySlash,
        scanCount: logItems.length,
        positions: formatted,
        // currentCapital calculated by UI
        dailyPnL: dailyPnL,
        totalProfit: totalPnL,
        status: logItems.length === 0 ? "EMPTY_LOGS" : "OK"
    }
};

// 無論輸入如何，都回傳一個成功 JSON
return {
    json: {
        success: true,
        message: "Virtual capital has been reset and logs cleared.",
        timestamp: new Date().toISOString()
    }
};
